import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Users, AlertTriangle, TrendingUp, 
  Calendar, ShoppingCart, DollarSign, Target, CheckCircle2 
} from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    totalEmAberto: 0,
    parcelasFuturas: 0,
    maiorParcelaMes: 0,
    totalGeral: 0,
    qtdComprasMes: 0,
    detalhesPorPessoa: {}
  });

  const hoje = new Date();
  const mesAtual = hoje.getMonth();
  const anoAtual = hoje.getFullYear();

  // Definição de cores vibrantes para o painel
  const colors = {
    primary: '#4361ee', // Azul Principal
    secondary: '#7209b7', // Roxo
    accent1: '#f72585', // Rosa Choque
    accent2: '#4cc9f0', // Ciano
    success: '#4caf50', // Verde
    warning: '#ff9800'  // Laranja
  };

  useEffect(() => {
    async function carregarIndicadores() {
      const { data } = await supabase.from('compras').select('*');
      if (!data) return;

      let resumo = {
        totalMes: 0, totalEmAberto: 0, parcelasFuturas: 0,
        maiorParcelaMes: 0, totalGeral: 0, qtdComprasMes: 0,
        detalhesPorPessoa: {}
      };

      data.forEach(item => {
        const valorTotal = parseFloat(item.valor_total);
        const numParcelas = item.num_parcelas || 1;
        const valorParcela = valorTotal / numParcelas;
        const dataCompra = new Date(item.data_compra);
        const responsavel = item.responsavel || 'Indefinido';

        // Inicializa objeto da pessoa se não existir
        if (!resumo.detalhesPorPessoa[responsavel]) {
          resumo.detalhesPorPessoa[responsavel] = {
            totalGeral: 0,
            qtdComprasMes: 0,
            ultimaParcelaDate: new Date(0),
            qtdTotalCompras: 0
          };
        }

        const p = resumo.detalhesPorPessoa[responsavel];
        resumo.totalGeral += valorTotal;
        p.totalGeral += valorTotal;
        p.qtdTotalCompras += 1;

        if (dataCompra.getMonth() === mesAtual && dataCompra.getFullYear() === anoAtual) {
          resumo.qtdComprasMes++;
          p.qtdComprasMes++;
        }

        for (let i = 0; i < numParcelas; i++) {
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela > p.ultimaParcelaDate) p.ultimaParcelaDate = dataParcela;

          if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
            resumo.totalMes += valorParcela;
            if (valorParcela > resumo.maiorParcelaMes) resumo.maiorParcelaMes = valorParcela;
          }

          if (dataParcela >= new Date(anoAtual, mesAtual, 1)) {
            resumo.totalEmAberto += valorParcela;
            resumo.parcelasFuturas++;
          }
        }
      });

      setStats(resumo);
    }

    carregarIndicadores();
  }, []);

  const formatMoney = (v) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ padding: '20px', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      
      {/* ================= PAINEL GERENCIAL ================= */}
      <h2 style={{ marginBottom: '25px', display: 'flex', alignItems: 'center', gap: '10px', color: '#333' }}>
        <TrendingUp size={28} color={colors.primary} /> Painel Gerencial de Despesas
      </h2>
      <div style={gridStyle}>
        <Card 
          title="Valor a pagar no mês" 
          icon={<Calendar size={22} />} 
          value={formatMoney(stats.totalMes)} 
          gradient={`linear-gradient(135deg, ${colors.primary}, ${colors.accent2})`} 
        />
        <Card 
          title="Total em aberto" 
          icon={<DollarSign size={22} />} 
          value={formatMoney(stats.totalEmAberto)} 
          gradient={`linear-gradient(135deg, ${colors.secondary}, ${colors.primary})`} 
        />
        <Card 
          title="Parcelas futuras" 
          icon={<CreditCard size={22} />} 
          value={stats.parcelasFuturas} 
          gradient={`linear-gradient(135deg, ${colors.accent2}, #3f37c9)`}
        />
        <Card 
          title="Compras no mês" 
          icon={<ShoppingCart size={22} />} 
          value={stats.qtdComprasMes} 
          gradient={`linear-gradient(135deg, ${colors.primary}, #560bad)`}
        />
        <Card 
          title="Maior parcela do mês" 
          icon={<AlertTriangle size={22} />} 
          value={formatMoney(stats.maiorParcelaMes)} 
          gradient={`linear-gradient(135deg, ${colors.warning}, ${colors.accent1})`}
        />
        <Card 
          title="Total histórico" 
          icon={<TrendingUp size={22} />} 
          value={formatMoney(stats.totalGeral)} 
          gradient={`linear-gradient(135deg, ${colors.accent1}, ${colors.secondary})`}
          highlight 
        />
      </div>

      {/* ================= GESTÃO POR PESSOA ================= */}
      <h2 style={{ margin: '50px 0 25px 0', display: 'flex', alignItems: 'center', gap: '10px', color: '#333' }}>
        <Users size={28} color={colors.secondary} /> Gestão Detalhada por Pessoa
      </h2>

      <div style={gridStyle}>
        {Object.entries(stats.detalhesPorPessoa)
          .sort((a, b) => b[1].totalGeral - a[1].totalGeral)
          .map(([nome, dados]) => {
            const percentual = stats.totalGeral ? ((dados.totalGeral / stats.totalGeral) * 100).toFixed(1) : 0;
            const mediaPorCompra = dados.totalGeral / dados.qtdTotalCompras;
            const quitacaoFormatada = dados.ultimaParcelaDate.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' });

            return (
              <div key={nome} className="card-pessoa" style={personCardStyle}>
                <div style={cardHeaderStyle}>
                  <div style={{ fontSize: '0.75rem', fontWeight: 800, color: colors.secondary, textTransform: 'uppercase', letterSpacing: '1.2px' }}>Responsável</div>
                  <div style={{ fontSize: '1.6rem', fontWeight: 700, color: '#2d3436', marginTop: '3px' }}>{nome}</div>
                </div>

                <div style={{ marginBottom: '25px', padding: '0 5px' }}>
                  <div style={{ fontSize: '0.9rem', color: '#636e72', fontWeight: 500 }}>Gasto Histórico Acumulado</div>
                  <div style={{ fontSize: '2rem', fontWeight: 800, color: colors.primary, marginTop: '5px' }}>{formatMoney(dados.totalGeral)}</div>
                  <div style={badgeStyle(`${colors.accent2}20`, colors.primary)}>{percentual}% da fatura total</div>
                </div>

                <div style={innerGridStyle}>
                  <MiniStat 
                    label="Compras Mês" 
                    value={dados.qtdComprasMes} 
                    sub="itens" 
                    icon={<ShoppingCart size={16} />} 
                    iconColor={colors.accent1}
                  />
                  <MiniStat 
                    label="Média/Compra" 
                    value={formatMoney(mediaPorCompra)} 
                    icon={<Target size={16} />} 
                    iconColor={colors.success}
                  />
                  <MiniStat 
                    label="Quitação em" 
                    value={quitacaoFormatada} 
                    icon={<CheckCircle2 size={16} />} 
                    highlightColor={colors.secondary}
                    iconColor={colors.warning}
                  />
                </div>
              </div>
            );
          })}
      </div>
    </div>
  );
};

/* COMPONENTES DE APOIO COM ESTILOS ATUALIZADOS */
const Card = ({ title, icon, value, gradient, highlight }) => (
  <div className="card" style={{
    padding: '25px',
    borderRadius: '16px',
    background: gradient,
    color: 'white',
    boxShadow: highlight ? '0 12px 20px -10px rgba(247, 37, 133, 0.5)' : '0 8px 15px -5px rgba(0,0,0,0.1)',
    transition: 'transform 0.3s ease, box-shadow 0.3s ease',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'space-between',
    minHeight: '140px',
    border: '1px solid rgba(255,255,255,0.1)'
  }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: '10px', fontSize: '0.75rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1px', opacity: 0.9 }}>
      {icon} {title}
    </div>
    <div style={{ fontSize: '1.9rem', fontWeight: 800, marginTop: '15px' }}>{value}</div>
  </div>
);

const MiniStat = ({ label, value, sub, icon, highlightColor, iconColor }) => (
  <div style={{ 
    padding: '12px', 
    backgroundColor: highlightColor ? `${highlightColor}10` : '#f8f9fa', 
    borderRadius: '12px',
    border: highlightColor ? `1px solid ${highlightColor}30` : '1px solid #eee',
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  }}>
    <div style={{ fontSize: '0.7rem', color: '#636e72', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '6px', textTransform: 'uppercase' }}>
      <span style={{color: iconColor}}>{icon}</span> {label}
    </div>
    <div style={{ fontSize: '1rem', fontWeight: 700, color: highlightColor ? highlightColor : '#2d3436' }}>
      {value} <span style={{ fontSize: '0.75rem', fontWeight: 400, color: '#636e72' }}>{sub}</span>
    </div>
  </div>
);

/* ESTILOS ATUALIZADOS */
const gridStyle = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
  gap: '25px'
};

const innerGridStyle = {
  display: 'grid',
  gridTemplateColumns: '1fr 1fr',
  gap: '12px'
};

const personCardStyle = {
  backgroundColor: 'white',
  padding: '25px',
  borderRadius: '20px',
  boxShadow: '0 15px 30px -10px rgba(0,0,0,0.05)',
  border: '1px solid #e1e8ed',
  transition: 'transform 0.3s ease',
  overflow: 'hidden',
  position: 'relative'
};

const cardHeaderStyle = {
  borderBottom: '2px solid #f0f2f5',
  paddingBottom: '15px',
  marginBottom: '20px'
};

const badgeStyle = (bgColor, textColor) => ({
  display: 'inline-block',
  padding: '5px 10px',
  backgroundColor: bgColor,
  color: textColor,
  borderRadius: '8px',
  fontSize: '0.8rem',
  fontWeight: 600,
  marginTop: '8px'
});

export default Dashboard;
